import type { EditorView } from '@codemirror/view';
import { type RefObject, useEffect } from 'react';

import { usePinnedFilters } from './usePinnedFilters.js';
import {
  ANNOTATION_SUGGESTION_PIN,
  pinnedFiltersEffect,
} from '../../editor-state-configs/editor-config.js';
import type { FilterFieldSuggestion } from '../../suggestions/Suggestion.types.js';

/**
 * Syncs the namespaced store of the filter field to the suggestions.
 */
export function usePinnedFilterSuggestions(
  editorViewRef: RefObject<EditorView>,
  filterNamespace: string | null = null,
  isOpen: boolean,
): void {
  const pinnedFilters = usePinnedFilters(filterNamespace);

  useEffect(() => {
    if (!editorViewRef.current) {
      return;
    }

    const pinnedFiltersSuggestions = pinnedFilters.map<FilterFieldSuggestion>(
      (storedFilter) => ({
        value: storedFilter.filter,
        insertionStrategy: 'replace-all',
        displayValue: storedFilter.filter,
      }),
    );

    editorViewRef.current.dispatch({
      userEvent: !isOpen ? undefined : ANNOTATION_SUGGESTION_PIN,
      effects: [pinnedFiltersEffect.of(pinnedFiltersSuggestions)],
    });
    // pinnedFilters needs to be stringified.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [editorViewRef.current, JSON.stringify(pinnedFilters)]);
}
